pub static VM_JAVA_CASES_TEST_EDGE_CASES__TESTCOMBINED_STRESS_TEST: &[JavaVmCase] = &[
    JavaVmCase { id: "TestEdgeCases.java:266:code_v4_.equals", kind: SourceKind::Snippet, source: "function buildTree(depth) { if (depth == 0) return ['leaf': true, 'data': [1, 2, 3]] return ['left': buildTree(depth - 1), 'right': buildTree(depth - 1), 'data': [depth]] } var tree = buildTree(3) return tree['data'][0]", expect: ExpectKind::ExportEqual { expected_export: "3" }, version_min: 4, version_max: 4, strict: false, max_ops_limit: None, max_ram_quads_limit: None },
    JavaVmCase { id: "TestEdgeCases.java:269:code_v4_.equals", kind: SourceKind::Snippet, source: "function transform(arr, depth) { if (depth == 0) return arr return transform(arrayMap(arr, x -> x * 2), depth - 1) } return transform([1, 2, 3, 4], 3)", expect: ExpectKind::ExportEqual { expected_export: "[8, 16, 24, 32]" }, version_min: 4, version_max: 4, strict: false, max_ops_limit: None, max_ram_quads_limit: None },
    JavaVmCase { id: "TestEdgeCases.java:272:code_v4_.equals", kind: SourceKind::Snippet, source: "function fib(n, memo) { if (n <= 1) return n if (memo[n] != null) return memo[n] memo[n] = fib(n - 1, memo) + fib(n - 2, memo) return memo[n] } any memo = [:] return fib(30, memo)", expect: ExpectKind::ExportEqual { expected_export: "832040" }, version_min: 4, version_max: 4, strict: false, max_ops_limit: None, max_ram_quads_limit: None },
];

pub static VM_JAVA_CASES_TEST_EDGE_CASES__TESTTOURNAMENTMINUSLIKE_STRESS_SCENARIOS: &[JavaVmCase] = &[
    JavaVmCase { id: "TestEdgeCases.java:283:code_v4_.equals", kind: SourceKind::Snippet, source: "var results = [] for (var round = 0; round < 8; round++) { var scores = [] for (var i = 0; i < 100; i++) push(scores, randInt(0, 1000)) push(results, arrayMax(scores)) } return count(results)", expect: ExpectKind::ExportEqual { expected_export: "8" }, version_min: 4, version_max: 4, strict: false, max_ops_limit: None, max_ram_quads_limit: None },
    JavaVmCase { id: "TestEdgeCases.java:286:code_v4_.equals", kind: SourceKind::Snippet, source: "function simulateFight() { var moves = [] for (var turn = 0; turn < 64; turn++) { push(moves, [randInt(0, 10), randInt(0, 10)]) } return randInt(0, 2) } var winners = [] for (var i = 0; i < 16; i++) { var winner = simulateFight() push(winners, winner) } return count(winners)", expect: ExpectKind::ExportEqual { expected_export: "16" }, version_min: 4, version_max: 4, strict: false, max_ops_limit: None, max_ram_quads_limit: None },
    JavaVmCase { id: "TestEdgeCases.java:289:code_v4_.equals", kind: SourceKind::Snippet, source: "function search(depth, alpha, beta, isMax) { if (depth == 0) return randInt(-100, 100) for (var i = 0; i < 3; i++) { var score = search(depth - 1, alpha, beta, !isMax) if (isMax) { alpha = max(alpha, score) } else { beta = min(beta, score) } if (beta <= alpha) break } return isMax ? alpha : beta } return search(5, -1000, 1000, true) >= -1000", expect: ExpectKind::ExportEqual { expected_export: "true" }, version_min: 4, version_max: 4, strict: false, max_ops_limit: None, max_ram_quads_limit: None },
];

